import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import '@fortawesome/fontawesome-free/css/all.min.css';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    toast.success('Logged out successfully!');
    navigate('/login');
  };

  return (
    <nav
      className="navbar navbar-expand-lg"
      style={{
        background: 'linear-gradient(90deg, #1e3c72 0%, #2a5298 100%)',
        boxShadow: '0 4px 24px 0 rgba(0, 0, 0, 0.15)',
        fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
        borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
        zIndex: 1000
      }}
    >
      <div className="container-fluid d-flex justify-content-between align-items-center py-2">
        <div className="d-flex align-items-center">
          <a className="navbar-brand d-flex align-items-center fw-bold" href="/dashboard" style={{ 
            fontSize: '1.7rem', 
            color: '#fff', 
            letterSpacing: 1
          }}>
            <div style={{ 
              background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
              width: 40,
              height: 40,
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              marginRight: 12,
              boxShadow: '0 4px 8px rgba(0, 0, 0, 0.2)'
            }}>
              <i className="fas fa-rss text-white" style={{ fontSize: '1.3rem' }}></i>
            </div>
            
            <span>
              <span style={{ color: '#5470FF' }}>Loyal</span>
              <span style={{ color: '#dc3545' }}>string</span>
              <span style={{ color: 'white' }}> RFID Dashboard</span>
            </span>
          </a>
          
          <Link 
            to="/rfid-integration" 
            className="ms-4 nav-link fw-semibold text-white d-flex align-items-center" 
            style={{ 
              fontSize: '1.1rem', 
              opacity: 0.92, 
              transition: 'all 0.3s',
              position: 'relative',
              color: 'rgba(255, 255, 255, 0.85)'
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.color = '#fff';
              e.currentTarget.style.transform = 'translateY(-1px)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.color = 'rgba(255, 255, 255, 0.85)';
              e.currentTarget.style.transform = 'translateY(0)';
            }}
          >
            <div style={{ 
              background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
              width: 30,
              height: 30,
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              marginRight: 8,
              boxShadow: '0 3px 6px rgba(0, 0, 0, 0.1)'
            }}>
              <i className="fas fa-plug text-white" style={{ fontSize: '0.9rem' }}></i>
            </div>
            RFID Integration
          </Link>
        </div>
        
        <div className="d-flex align-items-center">
          {userInfo && (
            <div 
              className="text-white me-3 d-flex align-items-center px-3 py-2 rounded-4 shadow-sm" 
              style={{ 
                fontWeight: 500, 
                background: 'rgba(255, 255, 255, 0.1)',
                backdropFilter: 'blur(5px)',
                border: '1px solid rgba(255, 255, 255, 0.1)'
              }}
            >
              <div style={{ 
                background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
                width: 35,
                height: 35,
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                marginRight: 10,
                boxShadow: '0 3px 6px rgba(0, 0, 0, 0.1)'
              }}>
                <i className="fas fa-user text-white" style={{ fontSize: '0.9rem' }}></i>
              </div>
              
              <span className="me-3" style={{ fontSize: '1.1rem' }}>{userInfo.Username}</span>
              
              <span 
                className="badge px-3 py-2" 
                style={{ 
                  fontSize: '0.85em', 
                  fontWeight: 600, 
                  letterSpacing: 1,
                  background: 'linear-gradient(45deg, #dc3545, #ff4a54)',
                  color: 'white',
                  borderRadius: '8px'
                }}
              >
                <i className="fas fa-building me-1 text-white"></i>
                {userInfo.ClientCode || 'Not Available'}
              </span>
            </div>
          )}
          
          <button
            className="btn fw-bold shadow-sm ms-2"
            style={{
              background: 'linear-gradient(45deg, #dc3545, #ff4a54)',
              color: '#fff',
              border: 'none',
              fontSize: '1.05rem',
              letterSpacing: 1,
              padding: '0.5rem 1.2rem',
              borderRadius: 10,
              transition: 'all 0.3s',
              boxShadow: '0 4px 10px rgba(220, 53, 69, 0.3)'
            }}
            onClick={handleLogout}
            onMouseOver={e => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #c82333, #dc3545)';
              e.currentTarget.style.transform = 'translateY(-2px)';
              e.currentTarget.style.boxShadow = '0 6px 15px rgba(220, 53, 69, 0.4)';
            }}
            onMouseOut={e => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #dc3545, #ff4a54)';
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 4px 10px rgba(220, 53, 69, 0.3)';
            }}
          >
            <i className="fas fa-sign-out-alt me-2 text-white"></i>
            Logout
          </button>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </nav>
  );
};

export default Header;
